180	    // ReSharper disable once CppMemberFunctionMayBeStatic
181	    void barrier(const bool& use_comm_stream, const bool& with_cpu_sync, const bool& sequential = true) const {
182	        const auto compute_stream = at::cuda::getCurrentCUDAStream();
183	        const auto stream = use_comm_stream ? comm_stream : compute_stream;
184	        if (use_comm_stream)
185	            stream_wait(comm_stream, compute_stream);
186	
187	        // Wait all streams to finish on this GPU
188	        if (with_cpu_sync)
189	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
190	
191	        // Launch GPU barrier
192	        launch_barrier(nccl_context->dev_comm, nccl_context->window,
193	                       workspace,
194	                       nccl_context->scaleout_rank_idx, nccl_context->scaleup_rank_idx,
195	                       nccl_context->num_scaleout_ranks, nccl_context->num_scaleup_ranks,
196	                       num_gpu_timeout_cycles,
197	                       nccl_context->is_scaleup_nvlink,
198	                       sequential,
199	                       stream);
200	
201	        // Let CPU wait
202	        if (with_cpu_sync)
203	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
204	
205	        // Compute stream should also wait for the barrier
206	        if (use_comm_stream)
207	            stream_wait(compute_stream, comm_stream);
208	    }
