327	    void pp_set_config(const int64_t& num_max_tensor_bytes, const int& num_max_inflight_tensors) {
328	        // Flush previous operations
329	        barrier(false, true);
330	
331	        EP_HOST_ASSERT(num_max_tensor_bytes > 0 and num_max_inflight_tensors > 0);
332	        EP_HOST_ASSERT(num_max_tensor_bytes * num_max_inflight_tensors * 2 * 2 <= num_buffer_bytes);
333	        this->prev_rank_idx = (nccl_context->rank_idx + nccl_context->num_ranks - 1) % nccl_context->num_ranks;
334	        this->next_rank_idx = (nccl_context->rank_idx + 1) % nccl_context->num_ranks;
335	        this->num_max_pp_tensor_bytes = math::align<int64_t>(num_max_tensor_bytes, 32);
336	        this->num_max_pp_inflight_tensors = num_max_inflight_tensors;
337	    }
